package com.vidaysalud.veterinaria.recetaservicio.model;import jakarta.persistence.*;import lombok.*;@Entity @Table(name="detalle_receta",uniqueConstraints=@UniqueConstraint(name="uq_detalle_receta_medicamento",columnNames={"id_receta","id_medicamento"})) @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder public class DetalleReceta{@Id @GeneratedValue(strategy=GenerationType.IDENTITY)@Column(name="id_detalle")private Integer idDetalle;@ManyToOne(fetch=FetchType.LAZY,optional=false)@JoinColumn(name="id_receta",nullable=false)private Receta receta;@Column(name="id_medicamento",nullable=false)private Integer idMedicamento;@Column(nullable=false,length=100)private String dosis;@Column(length=100)private String frecuencia;@Column(length=100)private String duracion;@Lob private String indicaciones;}